command:
if (!actor) return;

const api = game.modules.get("custom-dnd5e").api;
api.counters.checkCheckbox(actor, "inspiration");

const t = token?.object ?? token;
if (!t) return;

canvas.interface.createScrollingText(t.center, "Inspired!", {
  anchor: CONST.TEXT_ANCHOR_POINTS.TOP,
  direction: CONST.TEXT_ANCHOR_POINTS.TOP,
  duration: 2500,
  fontFamily: "Modesto Condensed",
  fontSize: 36,
  fill: "#ffe066",
  stroke: "#000000",
  strokeThickness: 4
});
